const Q_BIOLOGY_2010=[{"id": "objective>Biology>2010>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">History</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject being done is Biology. This is evident from the context of the question and the category under which it falls.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2010>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following characterizes a matured plant cell?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The cytoplasm fills up the entire cell space</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus is pushed to the centre of the cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cell wall is made up of cellulose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus is small and irregular in shape</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mature plant cell is characterized by a cell wall made up of cellulose. The cell wall provides structural support and protection to the cell. The cytoplasm does not fill up the entire cell space as there are other organelles present. The nucleus is not necessarily pushed to the centre of the cell, and its shape can vary.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2010>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT a function of the nucleus of a cell?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It controls the life processes of the cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It translates genetic information for the manufacture of proteins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It stores and carries hereditary information</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is a reservoir of energy for the cell</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus of a cell does not serve as a reservoir of energy for the cell. The nucleus controls the life processes of the cell, translates genetic information for the manufacture of proteins, and stores and carries hereditary information. The mitochondria, not the nucleus, is often referred to as the powerhouse of the cell because it is responsible for producing energy.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2010>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dominant phase in the life cycle of a fern is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gametophyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prothallus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sporophyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">antheridium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the life cycle of a fern, the dominant phase is the sporophyte phase. This is the diploid phase that produces spores by meiosis. The gametophyte is the haploid phase that produces gametes, the prothallus is a type of gametophyte, and the antheridium is a structure that produces male gametes.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2010>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Parental care is exhibited by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">toads</div>", "<div style=\"font-family:Cambria;font-size:17px;\">snails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earthworms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birds</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds are known to exhibit parental care. They build nests, incubate eggs, and feed their young ones.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2010>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> With respect to their decreasing dependence on aquatic conditions for reproduction, which of the following is the correct arrangement of the  animals represented?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, IV, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV, Ill, II and I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, ll, IV and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III, II, IV and I</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In this order they depend less on water for reproduction. Fishes require water, rabbits are purely terrestrial.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2010>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the animals represents the oldest creature in terms of evolutionary history?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fish are the oldest creatures in terms of evolutionary history among the options given. They first appeared in the fossil record over 500 million years ago during the Cambrian period, long before crocodiles, frogs, or rabbits evolved.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2010>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups of cells is devoid of true nuclei?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Viruses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Algae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monera</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fungi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monera, which includes bacteria and cyanobacteria, lack a true nucleus. Their genetic material is not enclosed in a nuclear envelope. This characteristic is typical of prokaryotic cells.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : MONERA"}, {"id": "objective>Biology>2010>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The main function of the feathers covering the part labelled I is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent ectoparasites from attacking the animal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">generate heat to keep the animal warm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide some power for flight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">serve as insulator to maintain body heat</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of down feathers in birds is insulation. Down feathers are soft and fluffy, trapping air close to the bird's body to help maintain body heat and keep the bird warm. This is especially important in colder climates or during the winter months.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2010>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Based on the shape and structure of the beak and feet, the bird represented is <br/> likely to feed mainly on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">flesh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fruits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nectar</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds that feed on flesh, such as raptors (e.g., eagles, hawks, and owls), have distinctive adaptations in their beaks and feet suited for their carnivorous diet: <br/> Beak: They possess strong, hooked beaks that are sharp and curved. This design allows them to tear into flesh easily and effectively. The hooked tip helps in gripping and pulling apart their prey. <br/> Feet: Their feet are equipped with powerful, sharp talons (claws). These talons are used to catch, hold, and kill their prey. The feet are strong and muscular, providing a firm grip and the ability to exert significant pressure, which is crucial for subduing and holding onto their prey. <br/>  <br/> These adaptations make these birds efficient hunters and consumers of meat. <br/> </div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2010>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true of the transverse section of a dicot stem?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The epidermis is completely encircled by the cortex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The xylem is more interiorly located than the phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cambium lies between the cortex and the vascular bundles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The vascular bundles are randomly scattered within the cortex</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a dicot stem, the vascular bundles are arranged in a ring, with the xylem facing the interior and the phloem facing the exterior. The cambium, a layer of cells that contribute to secondary growth, is located between the xylem and phloem.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2010>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The movement of material in the xylem and phloem tissues of the plant is represented by the arrows labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III and IV respectively</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and I respectively</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II respectively</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV and III respectively</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Xylem transports water and minerals up to the plants from the root, phloem transports food down to the root from the leaves.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2010>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> During photosynthesis, the arrow labelled II represents the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">escape of mineral salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absorption of energy from the sun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">release of carbon(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">release of oxygen as a by-product</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During photosynthesis, the arrow labelled II represents the release of oxygen as a by-product. <br/> Oxygen is the by product of photosynthesis.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2010>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is lacking in the diet of a person with kwashiorkor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Vitamins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Proteins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbohydrates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Minerals</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kwashiorkor is a form of severe protein malnutrition characterized by edema, and an enlarged liver with fatty infiltrates. It is caused by insufficient protein intake in the presence of adequate energy intake. Therefore, the diet of a person with kwashiorkor is lacking in proteins.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2010>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mode of nutrition of sundew and bladderwort can be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">autotrophic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holozoic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemosynthetic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Holozoic nutrition in carnivorous plants involves capturing and digesting animal matter to supplement nutrient-poor diets. The process includes: <br/>  <br/> 1. Capture: Using specialized structures (e.g., sticky leaves or traps) to catch prey. <br/> 2. Digestion: Secreting enzymes to break down the prey's body. <br/> 3. Absorption: Taking up the digested nutrients, mainly nitrogen and phosphorus, through the leaves. <br/>  <br/> This adaptation helps them thrive in environments with low soil nutrients.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2010>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a mixture of a food substance and Benedict's solution was warmed, the solution changed from blue to brick-red. This indicates the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reducing sugar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fatty acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sucrose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amino acid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Benedict's solution is a chemical reagent named after the American chemist Stanley Rossiter Benedict. It is used to test for the presence of reducing sugars. When a food substance is mixed with Benedict's solution and heated, a color change from blue to brick-red indicates the presence of reducing sugars.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2010>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary structure responsible for pumping blood for circulation through the <br/> mammalian circulatory systems is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">veins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">right auricle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arteries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">left ventricle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The left ventricle is the primary structure responsible for pumping blood for circulation through the mammalian circulatory systems. It receives oxygenated blood from the left atrium and pumps it to the rest of the body under high pressure.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2010>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Circulation of blood to all parts of the body except the lungs is through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the pulmonary artery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">systemic circulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the lymphatic system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pulmonary circulation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Systemic circulation is the part of the cardiovascular system which carries oxygenated blood away from the heart to the body, and returns deoxygenated blood back to the heart. This circulation is responsible for transporting blood to all parts of the body except the lungs.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2010>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Yeast respires anaerobically to convert simple sugar to carbon(IV) oxide and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Yeast respires anaerobically (without oxygen) to convert simple sugar to carbon(IV) oxide and alcohol. This process is known as fermentation.</div>", "topic": "RESPIRATION : ANAEROBIC RESPIRATION"}, {"id": "objective>Biology>2010>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sheet of muscle that separates the thoracic and the abdominal cavities is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diaphragm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intercostal muscle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pleural membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pericardium</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diaphragm is a sheet of internal skeletal muscle that extends across the bottom of the thoracic cavity. It separates the thoracic cavity, which contains the heart and lungs, from the abdominal cavity and performs an important function in respiration.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2010>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oily substance that lubricates the mammalian hair to keep it flexible and water repellent is secreted by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sweat glands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sebaceous glands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fatty cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granular layer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sebaceous glands are small oil-producing glands present in the skin of mammals. They are usually attached to hair follicles and release a fatty substance, sebum, into the follicular duct and thence to the surface of the skin. The sebum lubricates and waterproofs the hair and skin, and gives them a slight shine.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2010>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The outer layer of the kidney where the Bowman's capsules are found is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cortex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pelvis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medulla</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyramid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The outer layer of the kidney is known as the cortex. It contains the Bowman's capsules, which are a part of the nephrons, the functional units of the kidney. The Bowman's capsule encloses a cluster of tiny blood vessels—capillaries—called the glomerulus. The function of the Bowman's capsule is to perform the first step in the filtration of blood to form urine.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2010>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following stimuli is likely to elicit a nastic response in an organism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Touch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Light intensity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemical substances</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gravity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A nastic response in an organism is a non-directional response to a stimulus. Touch is likely to elicit a nastic response in an organism. For example, the closing of the leaves of the touch-me-not plant (Mimosa pudica) when touched is a nastic response. The other options, light intensity, chemical substances, and gravity, can elicit other types of responses, but not necessarily nastic responses.</div>", "topic": "SUPPORT AND MOVEMENT : TROPIC TACTIC NASTIC AND SLEEP MOVEMENTS IN PLANTS"}, {"id": "objective>Biology>2010>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the male reproductive system of a mammal, sperm is stored in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">van deferens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urethra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">epididymis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seminiferous tubules</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the male reproductive system of a mammal, sperm is produced in the testes and then stored in the epididymis, where they mature. The vas deferens transports mature sperm to the urethra during ejaculation. Therefore, the epididymis is the correct answer.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2010>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chemosynthetic organisms are capable of manufacturing their food from simple inorganic substances through the process of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxidation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">denitrification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phosphorylation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chemosynthetic organisms are capable of manufacturing their food from simple inorganic substances through the process of oxidation. They use the energy released by chemical reactions to create a substance called ATP. ATP is used to fuel the creation of sugars, which can be used as an energy source. Therefore, oxidation is the correct answer.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2010>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the human gut that has an acidic content is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stomach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">duodenum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ileum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colon</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stomach is the part of the human gut that has an acidic content. This is due to the presence of gastric acid, which is primarily composed of hydrochloric acid. This acid helps in the digestion of food by breaking down proteins into smaller, more easily absorbed substances. It also kills or inhibits bacteria and other microorganisms in the food.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2010>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Stomata → Spirogyra  <br/> II. Alveoli → Earthworm  <br/> III. Malpighian tubule → Mammal  <br/> IV. Contractile vacuole → Protozoa   <br/> Which of the above structures is correctly matched with the organisms in which it is found?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct match is IV. Contractile vacuole → Protozoa. A contractile vacuole is an organelle in protozoa that expels excess water out of the cell. Stomata are found in plants, not in Spirogyra. Alveoli are found in the lungs of mammals, not in earthworms. Malpighian tubules are excretory organs found in insects, not in mammals.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2010>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A food chain always begins with a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decomposer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary consumer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A food chain always begins with a producer. Producers, also known as autotrophs, are organisms that can make their own food from sunlight (photosynthesis) or chemical energy (chemosynthesis). They form the base of the food chain by providing food for primary consumers.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2010>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mycorrhizae promote plant growth by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absorbing inorganic ions from the soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protecting it from infection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helping it to utilize atmospheric nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">serving as a growth regulator.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mycorrhizae are symbiotic relationships that form between fungi and plants. The fungi colonize the root system of a host plant, providing increased water and nutrient absorption capabilities while the plant provides the fungus with carbohydrates formed from photosynthesis. Therefore, the correct answer is that mycorrhizae promote plant growth by absorbing inorganic ions from the soil.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2010>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The barrier between maternal and foetal blood is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">placenta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">umbilical chord</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uterine wall</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The placenta is an organ that develops in the uterus during pregnancy. This structure provides oxygen and nutrients to the growing baby and removes waste products from the baby's blood. It is the barrier between maternal and foetal blood, preventing the two blood supplies from mixing.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2010>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The blood component that has the greatest affinity for oxygen is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lymphocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leucocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erythrocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thrombocytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Erythrocytes, also known as red blood cells, contain a protein called hemoglobin that carries oxygen from the lungs to all parts of the body. Hemoglobin has a high affinity for oxygen, making erythrocytes the blood component with the greatest affinity for oxygen.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2010>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms is mainly found in the marine habitat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Achatina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tilapia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dog fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tortoise</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Dog fish is a type of shark that is mainly found in marine habitats. Achatina (a type of snail) and Tilapia (a type of fish) can be found in freshwater habitats, and Tortoises are primarily land animals.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2010>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two halves of the pelvic girdle are joined together at the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pubic symphysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ilium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pubis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obturator foramen</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two halves of the pelvic girdle are joined together at the pubic symphysis. The pubic symphysis is a cartilaginous joint that is located between the left and right pubic bones near the midline of the body. The ilium, pubis, and obturator foramen are parts of the pelvic girdle, but they are not where the two halves of the girdle join. <br/> <img src=\"2010/78LLPR.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2010>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Adoption of appropriate nocturnal habits   <br/>  II. Burrowing  <br/>  Ill. Adjusting their internal body temperature   <br/>  IV. Possession of many sweat pores  <br/>  Which of the above are ways in which desert animals adapt to extreme heat of the environment?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Desert animals adapt to the extreme heat of the environment through various ways including adopting appropriate nocturnal habits (active during the night when it's cooler) and burrowing (to escape the heat during the day). Adjusting their internal body temperature is not a common adaptation for desert animals as maintaining a constant internal body temperature requires a lot of energy and water, which are scarce resources in the desert. Possession of many sweat pores is also not a common adaptation as sweating leads to water loss, which is not ideal in a desert environment.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2010>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Low annual rainfall, sparse vegetation, high diurnal temperatures and cold nights are characteristic features of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tropical rainforest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">montane forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guinea savanna</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristics described in the question are typical of a desert environment. Deserts are known for their low annual rainfall, sparse vegetation due to the harsh living conditions, high diurnal temperatures (hot days) due to the lack of cloud cover, and cold nights because the heat quickly escapes once the sun sets.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : DESERT"}, {"id": "objective>Biology>2010>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The average number of individuals of a species per unit area of the habitat is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">population density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population distribution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average number of individuals of a species per unit area of the habitat is referred to as the population density. This is a measure of how crowded or sparse a population is within a given area. It is calculated by dividing the total population by the area of the habitat.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2010>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The activity of an organism which affects the survival of another organism in the <br/> same habitat constitutes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an edaphic factor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an abiotic factor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a biotic factor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a physiographic factor</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The activity of an organism that affects the survival of another organism in the same habitat constitutes a biotic factor. Biotic factors are the living components of an ecosystem that affect the survival and evolution of organisms. These include interactions like predation, competition, and symbiosis.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2010>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The loss of soil through erosion can be reduced by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">watering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manuring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">irrigation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil erosion can be reduced by crop rotation. Crop rotation is the practice of growing different types of crops in the same area in sequential seasons. It helps in reducing soil erosion and increases soil fertility and crop yield.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>2010>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vector for yellow fever is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aedes mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anopheles mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tsetse fly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blackfly</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The vector for yellow fever is the Aedes mosquito. A vector in epidemiology is an organism that does not cause disease itself but which spreads infection by conveying pathogens from one host to another. In the case of yellow fever, the Aedes mosquito is the vector, transmitting the yellow fever virus from one host to another.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2010>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The protozoan <span style=\"font-style:italic;\"> Plasmodium falciparum </span>is transmitted by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">female Anopheles mosquitoes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">female Aedes mosquitoes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">female Culex mosquitoes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">female blackfly</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The protozoan <span style=\"font-style:italic;\"> Plasmodium falciparum </span>, which causes the most severe form of malaria, is transmitted by female Anopheles mosquitoes. The mosquito acts as a vector, carrying the parasite from one host to another.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2010>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A dilute solution of phenylthiocarbamide tastes bitter to some people and is <br/> tasteless to others. This is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">taste bud variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discontinuous variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morphological variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous variation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ability to taste phenylthiocarbamide (PTC) is a classic example of a trait that shows discontinuous variation. Discontinuous variation is a type of genetic variation where individuals fall into a number of distinct classes or categories, and is based on genetic factors. In this case, the ability to taste PTC is determined by a single gene with two alleles: tasting (T) and non-tasting (t).</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2010>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> In which plantation are all the trees between the height of 2m - 4m?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plantation III has trees between the height of 2m - 4m.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2010>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following is a true feature of plantation II?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It has the highest number of trees of about 2m high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It has the highest number of trees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It has the highest number of tall trees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The height of all its trees range between 2m and 6m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plantation II has the highest number of trees of about 2m high.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2010>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Thyroxine and Adrenalin are examples of hormones which control</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blood grouping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tongue rolling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">behavioural patterns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour variation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thyroxine and Adrenalin are hormones that control behavioural patterns. Thyroxine is a hormone the thyroid gland secretes into the bloodstream. Once in the bloodstream, thyroxine travels to the organs, like the liver and kidneys, where it increases the rate of the metabolic processes. Adrenalin, also known as adrenaline, is a hormone secreted by the adrenal glands, especially in conditions of stress, increasing rates of blood circulation, breathing, and carbohydrate metabolism and preparing muscles for exertion.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2010>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pair of genes that control a trait is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an allele</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recessive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dominant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a hybrid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A pair of genes that control a trait is referred to as an allele. An allele is one of two or more versions of a gene that are found at the same place on a chromosome. Alleles can exist in different versions, with small differences in the sequence of DNA base pairs that can lead to different traits.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2010>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chromosome number of a cell before and after the process of meiosis is <br/> conventionally represented as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2n → 2n</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n → n</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n → 2n</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2n → n</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Meiosis is a type of cell division that reduces the number of chromosomes in the parent cell by half and produces four gamete cells. This process is required to produce egg and sperm cells for sexual reproduction. During meiosis, the chromosome number changes from 2n (diploid) to n (haploid). So, the correct answer is '2n → n'.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2010>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If both parents are heterozygous for a trait,the probability that an offspring will be recessive for that trait is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In genetics, when both parents are heterozygous for a trait (Aa), the possible combinations for their offspring can be AA, Aa, aA, or aa. The probability of an offspring being homozygous recessive (aa) is 1 out of 4, or 1/4. So, the correct answer is '1/4'.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2010>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At what stage in the life history of a mammal is the sex of an individual set?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">At adolescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At puberty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At birth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At conception</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sex of a mammal is determined at the time of conception. This is because the sex chromosomes, X and Y, are responsible for determining the sex of an individual. Females have two X chromosomes (XX) and males have one X and one Y chromosome (XY). The sperm, which can carry either an X or a Y chromosome, determines the sex of the offspring at the time of conception. So, the correct answer is 'At conception'.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>2010>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main distinguishing features between the soldier termite and other members of the caste are the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">presence of wings, possession of a small head and large thorax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of wings, possession of a large thorax and a small head</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of wings, possession of strong mandibles and a large head</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of wings, possession of big head and the absence of mandibles</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The soldier termite is characterized by its absence of wings, possession of strong mandibles and a large head. These features help it in its primary role of defending the colony. The mandibles are used for fighting off predators and the large head houses the muscles that power the mandibles.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2010>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The flippers of a whale and the fins of a fish are examples of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">divergent evolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coevolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convergent evolution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The flippers of a whale and the fins of a fish are examples of convergent evolution. Convergent evolution is a process in which organisms not closely related (not monophyletic), independently evolve similar traits as a result of having to adapt to similar environments or ecological niches.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}];
